  1→{{ 'section-hero-banner.css' | asset_url | stylesheet_tag }}
  2→
  3→<div class="hero-banner reveal-on-scroll" style="--overlay-opacity: {{ section.settings.overlay_opacity | divided_by: 100.0 }};">
  4→  {%- if section.settings.background_image != blank -%}
  5→    <img
  6→      class="hero-banner__image"
  7→      src="{{ section.settings.background_image | image_url: width: 1920 }}"
  8→      srcset="
  9→        {{ section.settings.background_image | image_url: width: 768 }} 768w,
 10→        {{ section.settings.background_image | image_url: width: 1200 }} 1200w,
 11→        {{ section.settings.background_image | image_url: width: 1920 }} 1920w
 12→      "
 13→      sizes="100vw"
 14→      alt="{{ section.settings.background_image.alt | escape }}"
 15→      loading="eager"
 16→      fetchpriority="high"
 17→      width="{{ section.settings.background_image.width }}"
 18→      height="{{ section.settings.background_image.height }}"
 19→    >
 20→  {%- else -%}
 21→    <div class="hero-banner__placeholder">
 22→      {{ 'lifestyle-2' | placeholder_svg_tag: 'hero-banner__placeholder-svg' }}
 23→    </div>
 24→  {%- endif -%}
 25→
 26→  <div class="hero-banner__overlay"></div>
 27→
 28→  <div class="hero-banner__content page-width">
 29→    <h1 class="hero-banner__heading">{{ section.settings.heading }}</h1>
 30→    <p class="hero-banner__subheading">{{ section.settings.subheading }}</p>
 31→
 32→    <div class="hero-banner__cta-group">
 33→      <a
 34→        href="{{ section.settings.button_1_link }}"
 35→        class="hero-banner__cta hero-banner__cta--primary"
 36→      >
 37→        {{ section.settings.button_1_label }}
 38→      </a>
 39→      <a
 40→        href="{{ section.settings.button_2_link }}"
 41→        class="hero-banner__cta hero-banner__cta--secondary"
 42→      >
 43→        {{ section.settings.button_2_label }}
 44→      </a>
 45→    </div>
 46→
 47→    <div class="hero-banner__trust">
 48→      {%- if section.settings.trust_text_1 != blank -%}
 49→        <div class="hero-banner__trust-item">
 50→          <svg class="hero-banner__trust-icon" width="20" height="20" viewBox="0 0 20 20" fill="none" xmlns="http://www.w3.org/2000/svg">
 51→            <path d="M10 1L12.39 6.26L18 7.27L14 11.14L14.76 17L10 14.27L5.24 17L6 11.14L2 7.27L7.61 6.26L10 1Z" fill="#E8922A"/>
 52→          </svg>
 53→          <span>{{ section.settings.trust_text_1 }}</span>
 54→        </div>
 55→      {%- endif -%}
 56→      {%- if section.settings.trust_text_2 != blank -%}
 57→        <div class="hero-banner__trust-item">
 58→          <svg class="hero-banner__trust-icon" width="20" height="20" viewBox="0 0 20 20" fill="none" xmlns="http://www.w3.org/2000/svg">
 59→            <path d="M10 1L12.39 6.26L18 7.27L14 11.14L14.76 17L10 14.27L5.24 17L6 11.14L2 7.27L7.61 6.26L10 1Z" fill="#E8922A"/>
 60→          </svg>
 61→          <span>{{ section.settings.trust_text_2 }}</span>
 62→        </div>
 63→      {%- endif -%}
 64→      {%- if section.settings.trust_text_3 != blank -%}
 65→        <div class="hero-banner__trust-item">
 66→          <svg class="hero-banner__trust-icon" width="20" height="20" viewBox="0 0 20 20" fill="none" xmlns="http://www.w3.org/2000/svg">
 67→            <path d="M10 1L12.39 6.26L18 7.27L14 11.14L14.76 17L10 14.27L5.24 17L6 11.14L2 7.27L7.61 6.26L10 1Z" fill="#E8922A"/>
 68→          </svg>
 69→          <span>{{ section.settings.trust_text_3 }}</span>
 70→        </div>
 71→      {%- endif -%}
 72→    </div>
 73→  </div>
 74→</div>
