 76→<style>
 77→  .hero-banner {
 78→    position: relative;
 79→    width: 100%;
 80→    height: 100vh;
 81→    display: flex;
 82→    align-items: flex-end;
 83→    justify-content: center;
 84→    overflow: hidden;
 85→    color: #FFFFFF;
 86→  }
 87→
 88→  .hero-banner__image {
 89→    position: absolute;
 90→    top: 0;
 91→    left: 0;
 92→    width: 100%;
 93→    height: 100%;
 94→    object-fit: cover;
 95→    z-index: 1;
 96→  }
 97→
 98→  .hero-banner__placeholder {
 99→    position: absolute;
100→    top: 0;
101→    left: 0;
102→    width: 100%;
103→    height: 100%;
104→    background-color: #1A4D2E;
105→    z-index: 1;
106→  }
107→
108→  .hero-banner__placeholder-svg {
109→    width: 100%;
110→    height: 100%;
111→    object-fit: cover;
112→  }
113→
114→  .hero-banner__overlay {
115→    position: absolute;
116→    top: 0;
117→    left: 0;
118→    width: 100%;
119→    height: 100%;
120→    background: linear-gradient(
121→      to top,
122→      rgba(26, 77, 46, var(--overlay-opacity, 0.75)) 0%,
123→      rgba(26, 77, 46, calc(var(--overlay-opacity, 0.75) * 0.5)) 40%,
124→      rgba(0, 0, 0, calc(var(--overlay-opacity, 0.75) * 0.2)) 100%
125→    );
126→    z-index: 2;
127→  }
128→
129→  .hero-banner__content {
130→    position: relative;
131→    z-index: 3;
132→    text-align: center;
133→    padding: 0 2rem 6rem;
134→    max-width: 800px;
135→  }
136→
137→  .hero-banner__heading {
138→    font-size: 3.5rem;
139→    font-weight: 700;
140→    line-height: 1.1;
141→    margin: 0 0 1rem;
142→    color: #FFFFFF;
143→    letter-spacing: -0.02em;
144→  }
145→
146→  .hero-banner__subheading {
147→    font-size: 1.25rem;
148→    font-weight: 400;
149→    line-height: 1.5;
150→    margin: 0 0 2rem;
151→    color: rgba(255, 255, 255, 0.9);
152→    max-width: 600px;
153→    margin-left: auto;
154→    margin-right: auto;
155→  }
156→
157→  .hero-banner__cta-group {
158→    display: flex;
159→    gap: 1rem;
160→    justify-content: center;
161→    flex-wrap: wrap;
162→    margin-bottom: 2.5rem;
163→  }
164→
165→  .hero-banner__cta {
166→    display: inline-block;
167→    padding: 1rem 2.5rem;
168→    font-size: 1.05rem;
169→    font-weight: 600;
170→    text-decoration: none;
171→    border-radius: 6px;
172→    transition: all 0.3s ease;
173→    cursor: pointer;
174→    border: 2px solid transparent;
175→  }
176→
177→  .hero-banner__cta--primary {
178→    background-color: #E8922A;
179→    color: #FFFFFF;
180→    border-color: #E8922A;
181→  }
182→
183→  .hero-banner__cta--primary:hover {
184→    background-color: #d17e1e;
185→    border-color: #d17e1e;
186→    transform: translateY(-2px);
187→    box-shadow: 0 4px 12px rgba(232, 146, 42, 0.4);
188→  }
189→
190→  .hero-banner__cta--secondary {
191→    background-color: transparent;
192→    color: #FFFFFF;
193→    border-color: #FFFFFF;
194→  }
195→
196→  .hero-banner__cta--secondary:hover {
197→    background-color: #FFFFFF;
198→    color: #1A4D2E;
199→    transform: translateY(-2px);
200→    box-shadow: 0 4px 12px rgba(255, 255, 255, 0.3);
201→  }
202→
203→  .hero-banner__trust {
204→    display: flex;
205→    gap: 2rem;
206→    justify-content: center;
207→    flex-wrap: wrap;
208→  }
209→
210→  .hero-banner__trust-item {
211→    display: flex;
212→    align-items: center;
213→    gap: 0.5rem;
214→    font-size: 0.9rem;
215→    color: rgba(255, 255, 255, 0.85);
216→    font-weight: 500;
217→  }
218→
219→  .hero-banner__trust-icon {
220→    flex-shrink: 0;
221→  }
222→
223→  @media screen and (max-width: 749px) {
224→    .hero-banner {
225→      height: 70vh;
226→      align-items: center;
227→    }
228→
229→    .hero-banner__content {
230→      padding: 0 1.5rem;
231→    }
232→
233→    .hero-banner__heading {
234→      font-size: 2rem;
235→    }
236→
237→    .hero-banner__subheading {
238→      font-size: 1rem;
239→    }
240→
241→    .hero-banner__cta {
242→      padding: 0.85rem 1.75rem;
243→      font-size: 0.95rem;
244→      width: 100%;
245→      text-align: center;
246→    }
247→
248→    .hero-banner__trust {
249→      flex-direction: column;
250→      gap: 0.75rem;
251→      align-items: center;
252→    }
253→  }
254→</style>
