256→{% schema %}
257→{
258→  "name": "Hero Banner",
259→  "tag": "section",
260→  "class": "section-hero-banner",
261→  "settings": [
262→    {
263→      "type": "text",
264→      "id": "heading",
265→      "label": "Heading",
266→      "default": "Professional Property Services"
267→    },
268→    {
269→      "type": "textarea",
270→      "id": "subheading",
271→      "label": "Subheading",
