281→      "id": "overlay_opacity",
282→      "label": "Overlay opacity",
283→      "min": 0,
284→      "max": 100,
285→      "step": 5,
286→      "default": 75,
287→      "unit": "%"
288→    },
289→    {
290→      "type": "text",
291→      "id": "button_1_label",
292→      "label": "Button 1 label",
293→      "default": "I'm Selling"
294→    },
295→    {
296→      "type": "url",
297→      "id": "button_1_link",
298→      "label": "Button 1 link"
299→    },
300→    {
301→      "type": "text",
302→      "id": "button_2_label",
303→      "label": "Button 2 label",
304→      "default": "I'm Renting"
305→    },
306→    {
307→      "type": "url",
308→      "id": "button_2_link",
309→      "label": "Button 2 link"
310→    },
311→    {
312→      "type": "text",
313→      "id": "trust_text_1",
314→      "label": "Trust indicator 1",
315→      "default": "500+ Properties Served"
316→    },
317→    {
318→      "type": "text",
319→      "id": "trust_text_2",
320→      "label": "Trust indicator 2",
321→      "default": "Rated 4.9/5"
322→    },
323→    {
324→      "type": "text",
325→      "id": "trust_text_3",
326→      "label": "Trust indicator 3",
327→      "default": "RICS Accredited"
328→    },
329→    {
330→      "type": "color_scheme",
331→      "id": "color_scheme",
332→      "label": "Colour scheme",
333→      "default": "scheme-1"
334→    }
335→  ],
336→  "presets": [
337→    {
338→      "name": "Hero Banner"
339→    }
340→  ]
341→}
342→{% endschema %}
