input.content:
{%- liquid
  assign overlay_opacity = section.settings.overlay_opacity | divided_by: 100.0
-%}

<section class="hero-banner" style="padding-top: {{ section.settings.padding_top }}px; padding-bottom: {{ section.settings.padding_bottom }}px;">
  <div class="hero-banner__media">
    {%- if section.settings.background_image != blank -%}
      <img
        class="hero-banner__image"
        src="{{ section.settings.background_image | image_url: width: 1920 }}"
        srcset="{{ section.settings.background_image | image_url: width: 768 }} 768w, {{ section.settings.background_image | image_url: width: 1200 }} 1200w, {{ section.settings.background_image | image_url: width: 1920 }} 1920w"
        sizes="100vw"
        alt="{{ section.settings.background_image.alt | escape }}"
        loading="eager"
        fetchpriority="high"
        width="{{ section.settings.background_image.width }}"
        height="{{ section.settings.background_image.height }}"
      >
    {%- else -%}
      <div class="hero-banner__placeholder"></div>
    {%- endif -%}
    <div class="hero-banner__overlay" style="background-color: rgba(26, 77, 46, {{ overlay_opacity }});"></div>
  </div>

  <div class="hero-banner__content page-width">
    <h1 class="hero-banner__heading">{{ section.settings.heading }}</h1>
    <p class="hero-banner__subheading">{{ section.settings.subheading }}</p>

    <div class="hero-banner__buttons">
      {%- if section.settings.button_1_label != blank -%}
        <a href="{{ section.settings.button_1_link }}" class="hero-banner__btn hero-banner__btn--primary">
          {{ section.settings.button_1_label }}
        </a>
      {%- endif -%}
      {%- if section.settings.button_2_label != blank -%}
        <a href="{{ section.settings.button_2_link }}" class="hero-banner__btn hero-banner__btn--secondary">
          {{ section.settings.button_2_label }}
        </a>
      {%- endif -%}
    </div>
  </div>

  <div class="hero-banner__trust-bar">
    <div class="page-width">
      <div class="hero-banner__trust-row">
        {%- if section.settings.trust_text_1 != blank -%}
          <span class="hero-banner__trust-item">{{ section.settings.trust_text_1 }}</span>
        {%- endif -%}
        {%- if section.settings.trust_text_2 != blank -%}
          <span class="hero-banner__trust-item">{{ section.settings.trust_text_2 }}</span>
        {%- endif -%}
        {%- if section.settings.trust_text_3 != blank -%}
          <span class="hero-banner__trust-item">{{ section.settings.trust_text_3 }}</span>
        {%- endif -%}
      </div>
    </div>
  </div>
</section>

{% schema %}
{
  "name": "Hero Banner",
  "tag": "div",
  "class": "section-hero-banner",
  "settings": [
    {
      "type": "text",
      "id": "heading",
      "label": "Heading",
      "default": "Professional Property Services"
    },
    {
      "type": "textarea",
      "id": "subheading",
      "label": "Subheading",
      "default": "Expert legal, survey & marketing services for landlords and sellers"
    },
    {
      "type": "image_picker",
      "id": "background_image",
      "label": "Background image"
    },
    {
      "type": "range",
      "id": "overlay_opacity",
      "label": "Overlay opacity",
      "min": 0,
      "max": 100,
      "step": 5,
      "default": 40,
      "unit": "%"
    },
    {
      "type": "text",
      "id": "button_1_label",
      "label": "Button 1 label",
      "default": "I'm Selling"
    },
    {
      "type": "url",
      "id": "button_1_link",
      "label": "Button 1 link"
    },
    {
      "type": "text",
      "id": "button_2_label",
      "label": "Button 2 label",
      "default": "I'm Renting"
    },
    {
      "type": "url",
      "id": "button_2_link",
      "label": "Button 2 link"
    },
    {
      "type": "text",
      "id": "trust_text_1",
      "label": "Trust indicator 1",
      "default": "500+ Properties Served"
    },
    {
      "type": "text",
      "id": "trust_text_2",
      "label": "Trust indicator 2",
      "default": "Rated 4.9/5"
    },
    {
      "type": "text",
      "id": "trust_text_3",
      "label": "Trust indicator 3",
      "default": "RICS Accredited"
    },
    {
      "type": "color_scheme",
      "id": "color_scheme",
      "label": "Colour scheme",
      "default": "scheme-1"
    },
    {
      "type": "range",
      "id": "padding_top",
      "label": "Padding top",
      "min": 0,
      "max": 100,
      "step": 4,
      "default": 0,
      "unit": "px"
    },
    {
      "type": "range",
      "id": "padding_bottom",
      "label": "Padding bottom",
      "min": 0,
      "max": 100,
      "step": 4,
      "default": 0,
      "unit": "px"
    }
  ],
  "presets": [
    {
      "name": "Hero Banner"
    }
  ]
}
{% endschema %}
